/* ═══════════════════════════════════════════════════════════════════════════
   TradingJournalPage — Real trading journal wired to backend APIs
   ═══════════════════════════════════════════════════════════════════════════
   Data Sources:
     GET /api/positions         — closed positions (trade log)
     GET /api/orders/blotter    — order fills
     GET /api/track-record/outcomes  — trade outcomes + strategy attribution
     GET /api/track-record/summary   — performance summary
     GET /api/accounts/pnl      — P&L data
     GET /api/aura_alpha/big-wins    — biggest winners
     GET /api/ai/journal-insights    — AI-generated insights
   ═══════════════════════════════════════════════════════════════════════════ */

const T = tokens;

// ── Formatters ──────────────────────────────────────────────────────────
const fmt = (n) => Number(n || 0).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
const fmtPct = (n) => `${(Number(n || 0) * 100).toFixed(1)}%`;
const pnlColor = (pnl) =>
  pnl > 0 ? T.color.green : pnl < 0 ? T.color.red : T.color.textSecondary;
const pnlSign = (pnl) => pnl >= 0 ? '+' : '';

// ── Date helpers ────────────────────────────────────────────────────────
function getDaysInMonth(year, month) { return new Date(year, month + 1, 0).getDate(); }
function getFirstDayOfWeek(year, month) { return new Date(year, month, 1).getDay(); }
function toISODate(d) { return d.toISOString().split('T')[0]; }
function getWeekNumber(d) {
  const date = new Date(d);
  date.setHours(0, 0, 0, 0);
  date.setDate(date.getDate() + 3 - (date.getDay() + 6) % 7);
  const week1 = new Date(date.getFullYear(), 0, 4);
  return 1 + Math.round(((date - week1) / 86400000 - 3 + (week1.getDay() + 6) % 7) / 7);
}

