// ── Utility: compute stats from an array of trades ──────────────────────
function computeStats(trades) {
  const pnls = trades.map(t => t.pnl || 0);
  const wins = pnls.filter(p => p > 0);
  const losses = pnls.filter(p => p < 0);
  const totalWins = wins.reduce((s, p) => s + p, 0);
  const totalLosses = Math.abs(losses.reduce((s, p) => s + p, 0));

  return {
    total_trades: pnls.length,
    win_rate: pnls.length > 0 ? wins.length / pnls.length : null,
    total_pnl: pnls.reduce((s, p) => s + p, 0),
    profit_factor: totalLosses > 0 ? (totalWins / totalLosses).toFixed(2) : pnls.length > 0 ? 'Inf' : '--',
    avg_win: wins.length > 0 ? totalWins / wins.length : 0,
    avg_loss: losses.length > 0 ? losses.reduce((s, p) => s + p, 0) / losses.length : 0,
    best_trade: pnls.length > 0 ? Math.max(...pnls) : 0,
    worst_trade: pnls.length > 0 ? Math.min(...pnls) : 0,
  };
}
